+        }
+      }
+      // Handle tail
+      for (uint32_t i = aligned_size + tx; i < actual_chunk_size; i += BLOCK_THREADS) {
+        thread_sum += float(probs[row_idx * vocab_size + chunk_start + i]);
+      }
